import pytest

def test_referral_decision_table_consent_and_role_combinations(
    clinician_auth_headers, nurse_auth_headers, api_client, ensure_consent
):
    ensure_consent(patient_id="P-001", granted=True)
    ensure_consent(patient_id="P-002", granted=False)

    # Row 1: wrong role (nurse), consent present → 403
    payload_nurse = {
        "resourceType": "ReferralRequest",
        "status": "active",
        "subject": {"reference": "Patient/P-001"},
        "recipient": [{"reference": "Organization/F-002"}]
    }
    resp_nurse = api_client.post("/ReferralRequest", json=payload_nurse, headers=nurse_auth_headers)
    assert resp_nurse.status_code == 403, (
        f"Nurse with consent: expected 403, got {resp_nurse.status_code}"
    )

    # Row 2: correct role (clinician), consent absent → 403
    payload_no_consent = {
        "resourceType": "ReferralRequest",
        "status": "active",
        "subject": {"reference": "Patient/P-002"},
        "recipient": [{"reference": "Organization/F-002"}]
    }
    resp_no_consent = api_client.post(
        "/ReferralRequest", json=payload_no_consent, headers=clinician_auth_headers
    )
    assert resp_no_consent.status_code == 403, (
        f"Clinician without consent: expected 403, got {resp_no_consent.status_code}"
    )
